def extract_items(dump: str) -> dict:
    lines_of_code = re.findall('(?:[^;"]*"[^"]+"[^;]*)|[^;]+', dump)
    item_definitions = {}

    def extract_string_property(property_name: str) -> str:
        return next(re.finditer(fr'{property_name}="([^"]*)"', line)).group(1)

    def extract_number_property(property_name: str) -> int | float:
        return parse_number(next(re.finditer(fr'{property_name}=(-?\d+|\d+(.\d+)?e\d+)$', line)).group(1), None)

    skipped_lines = set()
    new_item = {}
    for line in lines_of_code:
        if '.displayName=' in line:
            new_item['Name'] = extract_string_property('displayName').replace('_', ' ').replace('|', ' ')
        elif '.sellPrice=' in line:
            new_item['Sell Price'] = extract_number_property('sellPrice')
            pass
        elif '.typeGen=' in line:
            new_item['Code (Type)'] = extract_string_property('typeGen')
        elif '.Type=' in line:
            new_item['Type'] = extract_string_property('Type')
        elif '.lvReqToCraft=' in line:
            lv_req_to_craft = extract_string_property('lvReqToCraft')
            try:
                lv_req_to_craft = parse_number(lv_req_to_craft, -1)
                if lv_req_to_craft == -1:
                    continue
                new_item['Level Required (Craft)'] = lv_req_to_craft
            except:
                pass
        elif '.lvReqToEquip=' in line:
            new_item['Level Required (Equip)'] = extract_number_property('lvReqToEquip')
        elif '.Class=' in line:
            new_item['Class'] = extract_string_property('Class')
        elif '.Speed=' in line:
            new_item['Speed'] = extract_number_property('Speed')
        elif '.Reach=' in line:
            new_item['Reach'] = extract_number_property('Reach')
        elif '.Weapon_Power=' in line:
            new_item['Weapon Power'] = extract_number_property('Weapon_Power')
        elif '.STR=' in line:
            new_item['STR'] = extract_number_property('STR')
        elif '.AGI=' in line:
            new_item['AGI'] = extract_number_property('AGI')
        elif '.WIS=' in line:
            new_item['WIS'] = extract_number_property('WIS')
        elif '.LUK=' in line:
            new_item['LUK'] = extract_number_property('LUK')
        elif '.Defence=' in line:
            new_item['Defence'] = extract_number_property('Defence')
        elif results := re.findall(r'.UQ(\d)(txt|val)', line):
            slot, _type = results[0]
            translate_dict = {
                'txt': ['Text', extract_string_property],
                'val': ['Value', extract_number_property]
            }
            translated_type, target_function = translate_dict[_type]
            new_item[f'Misc {slot} ({translated_type})'] = target_function(f'UQ{slot}{_type}')
        elif '.Upgrade_Slots_Left=' in line:
            new_item['Upgrade Slots Left'] = extract_number_property('Upgrade_Slots_Left')
        elif slot := re.findall(r".desc_line(\d+)=", line):
            slot = slot[0]
            text = extract_string_property(f'desc_line{slot}')
            if 'Description' not in new_item:
                new_item['Description'] = {slot: text}
            else:
                new_item['Description'][slot] = text
        elif '.Effect="' in line:
            new_item['Effect'] = extract_string_property('Effect')
        elif '.Amount=' in line:
            new_item['Amount'] = extract_number_property('Amount')
        elif '.Trigger=' in line:
            new_item['Trigger'] = extract_number_property('Trigger')
        elif '.Cooldown=' in line:
            new_item['Cooldown'] = extract_number_property('Cooldown')
        elif 'addNew' in line:
            # this branch finishes the item. Do any "final parsing" of an item here
            new_item['Code (Name)'] = next(re.finditer(r'addNew\S+\("([^"]+)"', line)).group(1)

            # parse stamps
            if new_item['Type'] == "STAMP":
                _, scaling_type, x1, x2, _, material_code, _, _, _, _, _, effect, _ = new_item['Description']['1'].split(',')
                new_item['Stamp Bonus'] = {
                    'Effect': effect.replace('_', ' ').replace('{}', '').strip(),
                    'Scaling Type': scaling_type,
                    'x1': parse_number(x1, -1),
                    'x2': parse_number(x2, -1),
                    'Code (Material)': material_code,
                }

            # combine lines of description, replace placeholders, remove filler
            item_definitions[new_item['Code (Name)']] = new_item
            if 'Description' in new_item:
                new_item['Description'] = ' '.join(
                    [value for _, value in sorted(new_item['Description'].items(), key=lambda item: item[0]) if
                     value != 'Filler'])
                new_item['Description'] = new_item['Description'].replace('_', ' ')
            new_item = {}
        # explicitly skip any lines we don't need so we can crash in the `else` and devs are forced to look at this when the source changes
        elif any(re.findall(skippable, line) for skippable in [
            'itemDefs',  # initializes the definition scripts
            r'new[a-zA-Z]+\(\)?$',  # skip lines like `var = new l()` or `t = new l()`
            r'\.ID=',  # valid property, we just don't need it
            r'\.common=',  # seems to be a valid property but unclear what it does
            r'\.equip=',  # seems to be a valid property but unclear what it does
            r'\.consumable=',  # seems to be a valid property but unclear what it does
            '^$',  # empty lines
        ]):
            skipped_lines.add(line)  # Only for debugging. `skipped_lines` is deleted when this function ends
        else:
            raise NotImplementedError(f'Unhandled line `{line}`')

    # remove placeholders / not actually items
    del item_definitions['Blank']
    del item_definitions['null']
    del item_definitions['LockedInvSpace']

    del skipped_lines

    return item_definitions


generate_data_dict(
    script_item_definitions + script_item_definitions_2 + script_item_definitions_3 + script_item_definitions_4 + script_item_definitions_5 + script_item_definitions_6,
    extract_items, 'raw_item_data', raw_item_data)

ITEM_DATA: ItemDefinitions = ItemDefinitions()

for item_code, item in raw_item_data.items():
    if item_code == "_hash":
        continue
    name = item['Name']
    code_name = item['Code (Name)']
    _type = item['Type']
    description = item.get('Description', '')
    amount = item.get('Amount', None)

    if 'Stamp Bonus' in item:
        stamp_bonus = item['Stamp Bonus']
        ITEM_DATA[item['Code (Name)']] = StampItemDefinition(
            name=name,
            code_name=code_name,
            type=_type,
            description=description,
            amount=amount,
            stamp_bonus=StampBonus(
                effect=stamp_bonus['Effect'],
                code_material=stamp_bonus['Code (Material)'],
                scaling_type=stamp_bonus['Scaling Type'],
                x1=stamp_bonus['x1'],
                x2=stamp_bonus['x2']
            )
        )
        continue
    ITEM_DATA[item['Code (Name)']] = ItemDefinition(
        name=name,
        code_name=code_name,
        type=_type,
        description=description,
        amount=amount,
    )
